using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences to include in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;

    public int OriginalWordCount { get; set; }

    public int SummaryWordCount { get; set; }
}

using DocSummary.Models;

namespace DocSummary.Services;

public interface IDocumentSummarizationService
{
    SummarizeResponse Summarize(string documentText, int maxSentences);
}

using System.Text.RegularExpressions;
using DocSummary.Models;

namespace DocSummary.Services;

public partial class DocumentSummarizationService : IDocumentSummarizationService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "from", "it",
        "this", "that", "these", "those", "be", "been", "being", "have",
        "has", "had", "do", "does", "did", "will", "would", "could",
        "should", "may", "might", "shall", "can", "not", "no", "so",
        "if", "then", "than", "as", "its", "he", "she", "they", "we",
        "you", "i", "me", "my", "your", "his", "her", "our", "their",
        "what", "which", "who", "whom", "how", "when", "where", "why",
        "all", "each", "every", "both", "few", "more", "most", "other",
        "some", "such", "only", "own", "same", "about", "up", "out",
        "also", "just", "into", "over", "after", "before", "between"
    };

    public SummarizeResponse Summarize(string documentText, int maxSentences)
    {
        var sentences = SplitIntoSentences(documentText);
        int originalWordCount = CountWords(documentText);

        if (sentences.Count <= maxSentences)
        {
            return new SummarizeResponse
            {
                Summary = documentText.Trim(),
                OriginalWordCount = originalWordCount,
                SummaryWordCount = originalWordCount
            };
        }

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var scoredSentences = ScoreSentences(sentences, wordFrequencies);

        // Pick top-scoring sentences, preserving original order.
        var topSentences = scoredSentences
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index)
            .Select(s => s.Sentence.Trim());

        string summary = string.Join(" ", topSentences);

        return new SummarizeResponse
        {
            Summary = summary,
            OriginalWordCount = originalWordCount,
            SummaryWordCount = CountWords(summary)
        };
    }

    private static List<string> SplitIntoSentences(string text)
    {
        // Split on sentence-ending punctuation followed by whitespace or end-of-string.
        var parts = SentenceBoundary().Split(text);
        return parts
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (string sentence in sentences)
        {
            foreach (string word in ExtractWords(sentence))
            {
                if (!StopWords.Contains(word))
                    freq[word] = freq.GetValueOrDefault(word) + 1;
            }
        }
        return freq;
    }

    private static List<(string Sentence, int Index, double Score)> ScoreSentences(
        List<string> sentences,
        Dictionary<string, int> wordFrequencies)
    {
        int maxFreq = wordFrequencies.Count > 0 ? wordFrequencies.Values.Max() : 1;

        return sentences
            .Select((sentence, index) =>
            {
                double score = ExtractWords(sentence)
                    .Where(w => wordFrequencies.ContainsKey(w))
                    .Sum(w => (double)wordFrequencies[w] / maxFreq);

                // Normalize by word count to avoid bias toward longer sentences.
                int wordCount = CountWords(sentence);
                if (wordCount > 0)
                    score /= wordCount;

                return (Sentence: sentence, Index: index, Score: score);
            })
            .ToList();
    }

    private static IEnumerable<string> ExtractWords(string text) =>
        WordPattern().Matches(text).Select(m => m.Value);

    private static int CountWords(string text) =>
        WordPattern().Matches(text).Count;

    [GeneratedRegex(@"(?<=[.!?])\s+")]
    private static partial Regex SentenceBoundary();

    [GeneratedRegex(@"\b[a-zA-Z]+\b")]
    private static partial Regex WordPattern();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly IDocumentSummarizationService _summarizationService;

    public SummarizeController(IDocumentSummarizationService summarizationService)
    {
        _summarizationService = summarizationService;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.DocumentText))
            return BadRequest(new { error = "DocumentText must not be empty or whitespace." });

        var response = _summarizationService.Summarize(request.DocumentText, request.MaxSentences);
        return Ok(response);
    }
}

